{
  "name": "NutriFun AI",
  "description": "Une application ludique et simple pour suivre vos calories et macronutriments, propulsée par l'IA Gemini pour une estimation rapide des repas."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum MealType {
  BREAKFAST = 'Petit Déjeuner',
  LUNCH = 'Déjeuner',
  DINNER = 'Dîner',
  SNACK = 'En-cas'
}

export interface FoodItem {
  id: string;
  name: string;
  calories: number;
  protein: number;
  carbs: number;
  fat: number;
  quantity?: string;
}

export interface MealLog {
  id: string;
  type: MealType;
  items: FoodItem[];
  timestamp: number;
}

export interface DailyStats {
  date: string; // YYYY-MM-DD
  totalCalories: number;
  totalProtein: number;
  totalCarbs: number;
  totalFat: number;
  logs: MealLog[];
  waterIntake: number; // in glasses
}

export interface UserGoal {
  calories: number;
  protein: number;
  carbs: number;
  fat: number;
}

import { MealType, UserGoal } from './types';

export const DEFAULT_GOAL: UserGoal = {
  calories: 2000,
  protein: 150,
  carbs: 200,
  fat: 70
};

export const MEAL_TYPES_LIST = [
  MealType.BREAKFAST,
  MealType.LUNCH,
  MealType.DINNER,
  MealType.SNACK
];

export const STORAGE_KEY = 'nutrifun_data_v1';
export const USER_SETTINGS_KEY = 'nutrifun_settings_v1';

import { GoogleGenAI, Type } from "@google/genai";
import { FoodItem } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeFoodText = async (text: string): Promise<FoodItem | null> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Tu es un expert nutritionniste. Analyse le texte suivant décrivant un aliment ou un repas et estime ses valeurs nutritionnelles. Texte: "${text}". Sois réaliste.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING, description: "Nom court et clair de l'aliment" },
            calories: { type: Type.INTEGER, description: "Estimation des calories (kcal)" },
            protein: { type: Type.NUMBER, description: "Protéines en grammes" },
            carbs: { type: Type.NUMBER, description: "Glucides en grammes" },
            fat: { type: Type.NUMBER, description: "Lipides en grammes" },
            quantity: { type: Type.STRING, description: "Quantité estimée (ex: 100g, 1 portion)" }
          },
          required: ["name", "calories", "protein", "carbs", "fat"]
        }
      }
    });

    const jsonText = response.text;
    if (!jsonText) return null;

    const data = JSON.parse(jsonText);

    return {
      id: crypto.randomUUID(),
      ...data
    };
  } catch (error) {
    console.error("Erreur lors de l'analyse Gemini:", error);
    return null;
  }
};

export const getMotivationalMessage = async (caloriesLeft: number, streak: number): Promise<string> => {
    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `Génère une phrase courte, amusante et motivante (max 15 mots) pour un utilisateur qui suit son régime. 
            Contexte: Il lui reste ${caloriesLeft} calories aujourd'hui. Série actuelle: ${streak} jours.
            Ton: Amical, encourageant, un peu humoristique.`,
            config: {
                maxOutputTokens: 50,
            }
        });
        return response.text || "Continue comme ça !";
    } catch (e) {
        return "Tu es sur la bonne voie !";
    }
}

import React from 'react';

interface NutritionCardProps {
  label: string;
  value: number;
  total: number;
  color: string;
  unit?: string;
}

export const NutritionCard: React.FC<NutritionCardProps> = ({ label, value, total, color, unit = 'g' }) => {
  const percentage = Math.min(100, Math.max(0, (value / total) * 100));

  return (
    <div className="bg-white p-3 rounded-2xl shadow-sm border border-slate-100 flex flex-col items-center justify-center flex-1 min-w-[80px]">
      <span className="text-xs text-slate-400 font-semibold uppercase tracking-wider mb-1">{label}</span>
      <span className="text-lg font-display font-bold text-slate-700">
        {Math.round(value)}{unit}
      </span>
      <div className="w-full bg-slate-100 h-1.5 rounded-full mt-2 overflow-hidden">
        <div 
          className={`h-full rounded-full transition-all duration-500 ease-out`}
          style={{ width: `${percentage}%`, backgroundColor: color }}
        />
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { MealType, FoodItem } from '../types';
import { analyzeFoodText } from '../services/geminiService';

interface AddFoodModalProps {
  isOpen: boolean;
  onClose: () => void;
  onAddFood: (food: FoodItem, mealType: MealType) => void;
  selectedMealType: MealType;
}

export const AddFoodModal: React.FC<AddFoodModalProps> = ({ isOpen, onClose, onAddFood, selectedMealType }) => {
  const [inputMode, setInputMode] = useState<'manual' | 'ai'>('ai');
  const [aiInput, setAiInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [manualForm, setManualForm] = useState({
    name: '',
    calories: '',
    protein: '',
    carbs: '',
    fat: ''
  });

  if (!isOpen) return null;

  const handleAiSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!aiInput.trim()) return;

    setIsLoading(true);
    const result = await analyzeFoodText(aiInput);
    setIsLoading(false);

    if (result) {
      onAddFood(result, selectedMealType);
      setAiInput('');
      onClose();
    } else {
      alert("Désolé, je n'ai pas pu comprendre cet aliment. Essayez manuellement.");
    }
  };

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const food: FoodItem = {
      id: crypto.randomUUID(),
      name: manualForm.name,
      calories: parseInt(manualForm.calories) || 0,
      protein: parseFloat(manualForm.protein) || 0,
      carbs: parseFloat(manualForm.carbs) || 0,
      fat: parseFloat(manualForm.fat) || 0,
    };
    onAddFood(food, selectedMealType);
    setManualForm({ name: '', calories: '', protein: '', carbs: '', fat: '' });
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
      <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl overflow-hidden animate-fade-in-up">

        {/* Header */}
        <div className="bg-primary p-4 flex justify-between items-center text-white">
          <h2 className="font-display font-bold text-xl">Ajouter à {selectedMealType}</h2>
          <button onClick={onClose} className="p-1 hover:bg-white/20 rounded-full transition">
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-6 h-6">
              <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        {/* Tabs */}
        <div className="flex p-2 bg-slate-50 gap-2">
          <button 
            onClick={() => setInputMode('ai')}
            className={`flex-1 py-2 rounded-xl text-sm font-bold transition-colors ${inputMode === 'ai' ? 'bg-white text-primary shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
          >
            ✨ Assistant IA
          </button>
          <button 
            onClick={() => setInputMode('manual')}
            className={`flex-1 py-2 rounded-xl text-sm font-bold transition-colors ${inputMode === 'manual' ? 'bg-white text-primary shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
          >
            ✏️ Manuel
          </button>
        </div>

        <div className="p-6">
          {inputMode === 'ai' ? (
            <form onSubmit={handleAiSubmit} className="flex flex-col gap-4">
              <label className="block">
                <span className="text-slate-600 font-medium mb-1 block">Que mangez-vous ?</span>
                <textarea 
                  value={aiInput}
                  onChange={(e) => setAiInput(e.target.value)}
                  placeholder="Ex: Une banane et un yaourt nature..."
                  className="w-full border-2 border-slate-200 rounded-xl p-3 focus:border-primary focus:ring-0 outline-none resize-none h-32 transition-colors"
                />
              </label>
              <button 
                type="submit" 
                disabled={isLoading || !aiInput.trim()}
                className="bg-primary text-white font-bold py-3 rounded-xl hover:bg-emerald-600 disabled:opacity-50 disabled:cursor-not-allowed transition-all flex justify-center items-center gap-2"
              >
                {isLoading ? (
                  <>
                    <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                    </svg>
                    Analyse magique...
                  </>
                ) : 'Ajouter'}
              </button>
              <p className="text-xs text-slate-400 text-center">L'IA estimera les calories et macros pour vous.</p>
            </form>
          ) : (
            <form onSubmit={handleManualSubmit} className="flex flex-col gap-3">
              <input 
                type="text" 
                placeholder="Nom de l'aliment" 
                className="border-2 border-slate-200 rounded-xl p-3 focus:border-primary outline-none"
                value={manualForm.name}
                onChange={e => setManualForm({...manualForm, name: e.target.value})}
                required
              />
              <div className="grid grid-cols-2 gap-3">
                <input type="number" placeholder="Calories (kcal)" className="border-2 border-slate-200 rounded-xl p-3 focus:border-primary outline-none"
                  value={manualForm.calories} onChange={e => setManualForm({...manualForm, calories: e.target.value})} required />
                <input type="number" placeholder="Protéines (g)" className="border-2 border-slate-200 rounded-xl p-3 focus:border-primary outline-none"
                   value={manualForm.protein} onChange={e => setManualForm({...manualForm, protein: e.target.value})} />
                <input type="number" placeholder="Glucides (g)" className="border-2 border-slate-200 rounded-xl p-3 focus:border-primary outline-none"
                   value={manualForm.carbs} onChange={e => setManualForm({...manualForm, carbs: e.target.value})} />
                <input type="number" placeholder="Lipides (g)" className="border-2 border-slate-200 rounded-xl p-3 focus:border-primary outline-none"
                   value={manualForm.fat} onChange={e => setManualForm({...manualForm, fat: e.target.value})} />
              </div>
              <button type="submit" className="bg-primary text-white font-bold py-3 rounded-xl hover:bg-emerald-600 mt-2">
                Enregistrer
              </button>
            </form>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { BarChart, Bar, XAxis, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { format } from 'date-fns';
import { fr } from 'date-fns/locale';

import { DailyStats, MealLog, FoodItem, MealType, UserGoal } from './types';
import { DEFAULT_GOAL, STORAGE_KEY, MEAL_TYPES_LIST } from './constants';
import { getMotivationalMessage } from './services/geminiService';
import { NutritionCard } from './components/NutritionCard';
import { AddFoodModal } from './components/AddFoodModal';

const App: React.FC = () => {
  // --- State ---
  const [dailyStats, setDailyStats] = useState<Record<string, DailyStats>>({});
  const [currentDate, setCurrentDate] = useState<string>(format(new Date(), 'yyyy-MM-dd'));
  const [goal] = useState<UserGoal>(DEFAULT_GOAL);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedMealType, setSelectedMealType] = useState<MealType>(MealType.BREAKFAST);
  const [coachMessage, setCoachMessage] = useState<string>("Salut ! Prêt à manger sainement ?");
  const [streak, setStreak] = useState(0);

  // --- Effects ---

  // Load data on mount
  useEffect(() => {
    const savedData = localStorage.getItem(STORAGE_KEY);
    if (savedData) {
      try {
        const parsed = JSON.parse(savedData);
        setDailyStats(parsed);
      } catch (e) {
        console.error("Failed to parse storage", e);
      }
    }
  }, []);

  // Save data on change
  useEffect(() => {
    if (Object.keys(dailyStats).length > 0) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(dailyStats));
    }
  }, [dailyStats]);

  // Calculate Streak
  useEffect(() => {
    // Simple streak logic: consecutive days with at least one log
    let currentStreak = 0;
    const today = new Date();
    // Check backwards from yesterday
    for (let i = 0; i < 365; i++) {
        const d = new Date(today);
        d.setDate(today.getDate() - i);
        const dateStr = format(d, 'yyyy-MM-dd');

        // Skip checking today for streak break if empty, but count if full
        if (i === 0 && (!dailyStats[dateStr] || dailyStats[dateStr].logs.length === 0)) continue;

        if (dailyStats[dateStr] && dailyStats[dateStr].logs.length > 0) {
            currentStreak++;
        } else {
            break;
        }
    }
    setStreak(currentStreak);
  }, [dailyStats]);

  // Coach Message
  useEffect(() => {
    const fetchMessage = async () => {
        const currentStats = dailyStats[currentDate];
        const cals = currentStats ? currentStats.totalCalories : 0;
        const remaining = goal.calories - cals;
        const msg = await getMotivationalMessage(remaining, streak);
        setCoachMessage(msg);
    };
    fetchMessage();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentDate, dailyStats[currentDate]?.totalCalories]); // Only re-fetch if calories change significantly or date changes


  // --- Helpers ---
  const currentStats = useMemo(() => {
    if (!dailyStats[currentDate]) {
      return {
        date: currentDate,
        totalCalories: 0,
        totalProtein: 0,
        totalCarbs: 0,
        totalFat: 0,
        logs: [],
        waterIntake: 0
      } as DailyStats;
    }
    return dailyStats[currentDate];
  }, [dailyStats, currentDate]);

  const handleAddFood = (food: FoodItem, type: MealType) => {
    setDailyStats(prev => {
      const stats = prev[currentDate] || {
        date: currentDate,
        totalCalories: 0,
        totalProtein: 0,
        totalCarbs: 0,
        totalFat: 0,
        logs: [],
        waterIntake: 0
      };

      const newLogs = [...stats.logs];
      // Check if a meal log for this type already exists
      let mealLog = newLogs.find(l => l.type === type);

      if (!mealLog) {
        mealLog = { id: crypto.randomUUID(), type, items: [], timestamp: Date.now() };
        newLogs.push(mealLog);
      } else {
         // Create a new reference for the mealLog to trigger updates properly if nested
         mealLog = { ...mealLog, items: [...mealLog.items] };
         // We need to update the object in the array
         const index = newLogs.findIndex(l => l.type === type);
         newLogs[index] = mealLog;
      }

      mealLog.items.push(food);

      return {
        ...prev,
        [currentDate]: {
          ...stats,
          logs: newLogs,
          totalCalories: stats.totalCalories + food.calories,
          totalProtein: stats.totalProtein + food.protein,
          totalCarbs: stats.totalCarbs + food.carbs,
          totalFat: stats.totalFat + food.fat,
        }
      };
    });
  };

  const handleRemoveFood = (mealType: MealType, foodId: string) => {
    setDailyStats(prev => {
        const stats = prev[currentDate];
        if (!stats) return prev;

        const mealLog = stats.logs.find(l => l.type === mealType);
        if(!mealLog) return prev;

        const foodItem = mealLog.items.find(f => f.id === foodId);
        if (!foodItem) return prev;

        const newItems = mealLog.items.filter(f => f.id !== foodId);

        // If meal empty, remove meal log or keep empty? Let's keep empty for simplicity or remove.
        const newLogs = stats.logs.map(l => {
            if (l.type === mealType) {
                return { ...l, items: newItems };
            }
            return l;
        });

        return {
            ...prev,
            [currentDate]: {
                ...stats,
                logs: newLogs,
                totalCalories: stats.totalCalories - foodItem.calories,
                totalProtein: stats.totalProtein - foodItem.protein,
                totalCarbs: stats.totalCarbs - foodItem.carbs,
                totalFat: stats.totalFat - foodItem.fat,
            }
        }
    });
  };

  const handleWater = (amount: number) => {
    setDailyStats(prev => {
        const stats = prev[currentDate] || {
            date: currentDate, totalCalories: 0, totalProtein: 0, totalCarbs: 0, totalFat: 0, logs: [], waterIntake: 0
        };
        return {
            ...prev,
            [currentDate]: {
                ...stats,
                waterIntake: Math.max(0, stats.waterIntake + amount)
            }
        }
    });
  };

  const openAddModal = (type: MealType) => {
    setSelectedMealType(type);
    setIsModalOpen(true);
  };

  // Chart Data preparation
  const chartData = useMemo(() => {
    const data = [];
    for (let i = 6; i >= 0; i--) {
        const d = new Date();
        d.setDate(d.getDate() - i);
        const dStr = format(d, 'yyyy-MM-dd');
        data.push({
            name: format(d, 'EEE', { locale: fr }),
            calories: dailyStats[dStr]?.totalCalories || 0,
            goal: goal.calories
        });
    }
    return data;
  }, [dailyStats, goal.calories]);

  // --- Render ---
  return (
    <div className="min-h-screen bg-slate-50 pb-20 md:pb-0">

      {/* Top Navigation / Header */}
      <div className="bg-white sticky top-0 z-30 shadow-sm px-6 py-4 flex justify-between items-center">
        <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-primary rounded-lg flex items-center justify-center text-white font-bold text-lg">N</div>
            <h1 className="font-display font-bold text-xl text-slate-800">NutriFun</h1>
        </div>
        <div className="flex items-center gap-3">
            <div className="flex items-center gap-1 bg-orange-100 text-orange-600 px-3 py-1 rounded-full text-sm font-bold">
                🔥 {streak}
            </div>
            <input 
                type="date" 
                value={currentDate}
                onChange={(e) => setCurrentDate(e.target.value)}
                className="bg-slate-100 border-none rounded-lg py-1 px-3 text-sm font-semibold text-slate-600 outline-none"
            />
        </div>
      </div>

      <div className="max-w-3xl mx-auto p-4 space-y-6">

        {/* Coach Message */}
        <div className="bg-gradient-to-r from-indigo-500 to-purple-500 rounded-2xl p-4 text-white shadow-lg flex items-center gap-4 relative overflow-hidden">
            <div className="text-4xl">🤖</div>
            <div className="relative z-10">
                <p className="font-bold text-lg opacity-90">Coach IA</p>
                <p className="font-display text-xl">{coachMessage}</p>
            </div>
            <div className="absolute -right-4 -bottom-10 w-32 h-32 bg-white/10 rounded-full blur-2xl"></div>
        </div>

        {/* Main Calorie Ring & Macros */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {/* Calories Card */}
            <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 flex flex-col items-center justify-center relative overflow-hidden">
                <h2 className="text-slate-500 font-semibold mb-2">Calories Restantes</h2>
                <div className="relative w-40 h-40 flex items-center justify-center">
                    {/* Simple SVG Ring */}
                    <svg className="w-full h-full -rotate-90" viewBox="0 0 36 36">
                        <path className="text-slate-100" d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" fill="none" stroke="currentColor" strokeWidth="3" />
                        <path 
                            className="text-primary transition-all duration-1000 ease-out" 
                            strokeDasharray={`${Math.min(100, (currentStats.totalCalories / goal.calories) * 100)}, 100`} 
                            d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" 
                            fill="none" stroke="currentColor" strokeWidth="3" 
                        />
                    </svg>
                    <div className="absolute flex flex-col items-center">
                        <span className="text-3xl font-display font-bold text-slate-800">
                            {goal.calories - currentStats.totalCalories}
                        </span>
                        <span className="text-xs text-slate-400">kcal</span>
                    </div>
                </div>
                <div className="mt-2 text-sm text-slate-400">
                    Objectif: {goal.calories} • Mangé: {currentStats.totalCalories}
                </div>
            </div>

            {/* Macros Grid */}
            <div className="grid grid-cols-1 gap-3">
                 <div className="flex gap-3 h-full">
                    <NutritionCard label="Protéines" value={currentStats.totalProtein} total={goal.protein} color="#8b5cf6" />
                    <NutritionCard label="Glucides" value={currentStats.totalCarbs} total={goal.carbs} color="#f59e0b" />
                    <NutritionCard label="Lipides" value={currentStats.totalFat} total={goal.fat} color="#ef4444" />
                 </div>
                 {/* Water Tracker Mini */}
                 <div className="bg-blue-50 p-4 rounded-2xl flex items-center justify-between border border-blue-100">
                    <div className="flex items-center gap-3">
                        <span className="text-2xl">💧</span>
                        <div>
                            <p className="font-bold text-blue-900">Eau</p>
                            <p className="text-xs text-blue-600">{currentStats.waterIntake} verres</p>
                        </div>
                    </div>
                    <div className="flex gap-1">
                        <button onClick={() => handleWater(-1)} className="w-8 h-8 rounded-full bg-white text-blue-500 font-bold hover:bg-blue-100">-</button>
                        <button onClick={() => handleWater(1)} className="w-8 h-8 rounded-full bg-blue-500 text-white font-bold hover:bg-blue-600 shadow-md">+</button>
                    </div>
                 </div>
            </div>
        </div>

        {/* Meal Logging Section */}
        <div className="space-y-4">
            <h3 className="font-display font-bold text-xl text-slate-800">Repas d'aujourd'hui</h3>

            {MEAL_TYPES_LIST.map((type) => {
                const log = currentStats.logs.find(l => l.type === type);
                const items = log ? log.items : [];
                const mealCals = items.reduce((acc, i) => acc + i.calories, 0);

                return (
                    <div key={type} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 transition hover:shadow-md">
                        <div className="flex justify-between items-center mb-3">
                            <div className="flex items-center gap-3">
                                <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-xl
                                    ${type === MealType.BREAKFAST ? 'bg-orange-100 text-orange-500' : ''}
                                    ${type === MealType.LUNCH ? 'bg-green-100 text-green-500' : ''}
                                    ${type === MealType.DINNER ? 'bg-blue-100 text-blue-500' : ''}
                                    ${type === MealType.SNACK ? 'bg-purple-100 text-purple-500' : ''}
                                `}>
                                    {type === MealType.BREAKFAST && '🥐'}
                                    {type === MealType.LUNCH && '🥗'}
                                    {type === MealType.DINNER && '🍽️'}
                                    {type === MealType.SNACK && '🍎'}
                                </div>
                                <div>
                                    <h4 className="font-bold text-slate-700">{type}</h4>
                                    <p className="text-xs text-slate-400 font-medium">{mealCals} kcal</p>
                                </div>
                            </div>
                            <button 
                                onClick={() => openAddModal(type)}
                                className="w-8 h-8 rounded-full bg-slate-100 text-primary hover:bg-primary hover:text-white transition flex items-center justify-center"
                            >
                                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-5 h-5">
                                    <path strokeLinecap="round" strokeLinejoin="round" d="M12 4.5v15m7.5-7.5h-15" />
                                </svg>
                            </button>
                        </div>

                        {/* Food List */}
                        {items.length > 0 ? (
                            <ul className="space-y-2 pl-12">
                                {items.map((item) => (
                                    <li key={item.id} className="flex justify-between items-center group">
                                        <div>
                                            <p className="text-sm font-semibold text-slate-700">{item.name}</p>
                                            <p className="text-xs text-slate-400">{item.quantity} • {item.calories} kcal</p>
                                        </div>
                                        <button 
                                            onClick={() => handleRemoveFood(type, item.id)}
                                            className="text-red-400 opacity-0 group-hover:opacity-100 transition p-1 hover:bg-red-50 rounded"
                                        >
                                            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-4 h-4">
                                                <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
                                            </svg>
                                        </button>
                                    </li>
                                ))}
                            </ul>
                        ) : (
                            <p className="text-sm text-slate-300 pl-14 italic">Aucun aliment ajouté</p>
                        )}
                    </div>
                );
            })}
        </div>

        {/* Weekly Chart */}
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
             <h3 className="font-display font-bold text-lg text-slate-800 mb-4">Cette semaine</h3>
             <div className="h-48 w-full">
                <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={chartData}>
                        <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 12, fill: '#94a3b8'}} />
                        <Tooltip 
                            cursor={{fill: '#f1f5f9'}}
                            contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}} 
                        />
                        <Bar dataKey="calories" radius={[6, 6, 6, 6]} barSize={20}>
                            {chartData.map((entry, index) => (
                                <Cell key={`cell-${index}`} fill={entry.calories > entry.goal ? '#ef4444' : '#10b981'} />
                            ))}
                        </Bar>
                    </BarChart>
                </ResponsiveContainer>
             </div>
        </div>

      </div>

      <AddFoodModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)}
        onAddFood={handleAddFood}
        selectedMealType={selectedMealType}
      />
    </div>
  );
};

export default App;
